+        if (end < 0) end = @max(0, str_len + end);
+
+        // Clamp to valid range
+        start = @max(0, @min(start, str_len));
+        end = @max(start, @min(end, str_len));
+
+        // Extract substring
+        const start_idx: usize = @intCast(start);
+        const end_idx: usize = @intCast(end);
